sn_aia_tool.script:
(function(inputs) {
    var gr = new GlideRecordSecure('x_snc_medwc_auto_0_warranty_claim');
    if (!gr.get(inputs.claim_sys_id)) {
        return JSON.stringify({ status: 'error', message: 'Claim not found' });
    }
    var now = new GlideDateTime();
    var workNote = 'AI Agent Decision: ' + inputs.decision.toUpperCase() + '\n\n';
    workNote += 'Warranty Analysis:\n' + inputs.analysis + '\n\n';
    workNote += 'Policy Reference: ' + inputs.policy_reference + '\n\n';
    workNote += 'Decision made: ' + now.getDisplayValue();
    gr.work_notes = workNote;
    gr.update();
    return JSON.stringify({
        status: 'success',
        message: 'Work note added to claim ' + gr.getValue('number'),
        claim_number: gr.getValue('number')
    });
})(inputs);
